'use client'

import { Suspense, useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import MatchPlayer from "@/components/match/match-player"
import MatchInfo from "@/components/match/match-info" 
import { 
  ArrowLeft, 
  Maximize, 
  Minimize, 
  Share2, 
  Copy, 
  MessageSquare, 
  AlertTriangle,
  CheckCircle,
  Twitter,
  Facebook
} from "lucide-react"
import "@/styles/match.css"

// 🔥 IMPORT LANGUAGE HOOK
import { useLanguage } from "@/context/language-context"

function MatchPageContent() {
  const router = useRouter()
  const params = useParams()
  const matchId = String(params.id)
  const { t } = useLanguage()

  // --- STATES ---
  const [cinemaMode, setCinemaMode] = useState(false)
  const [chatAgreed, setChatAgreed] = useState(false)
  const [showEmbed, setShowEmbed] = useState(false)
  const [copied, setCopied] = useState(false)

  // --- EMBED CODE GENERATOR ---
  const embedCode = `<iframe src="https://reedstreams.com/embed/${matchId}" width="100%" height="500" frameborder="0" allowfullscreen></iframe>`

  const handleCopy = () => {
    navigator.clipboard.writeText(embedCode)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  return (
    <div style={{
      minHeight:'100vh', 
      background: cinemaMode ? '#000' : '#050505', 
      paddingBottom:'40px',
      transition: 'background 0.5s ease'
    }}>
      
      {/* 1. TOP NAV BAR (Hidden in Cinema Mode) */}
      {!cinemaMode && (
        <div style={{
          maxWidth:'1600px', 
          margin:'0 auto', 
          padding:'20px 20px 10px 20px', 
          display:'flex', 
          justifyContent:'space-between', 
          alignItems:'center'
        }}>
          <button 
              onClick={() => router.back()} 
              style={{
                background:'transparent', 
                border:'none', 
                color:'#888', 
                cursor:'pointer', 
                display:'flex', 
                alignItems:'center', 
                gap:'8px',
                fontSize:'13px', 
                fontWeight:'600',
                textTransform:'uppercase',
                transition: 'color 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.color = '#fff'}
              onMouseLeave={(e) => e.currentTarget.style.color = '#888'}
          >
              <ArrowLeft size={16} /> {t.back_to_home || "Back"}
          </button>

          {/* Discord / Feedback Buttons */}
          <div style={{display:'flex', gap:'10px'}}>
             <a href="https://discord.gg/yourlink" target="_blank" style={{
               background:'#5865F2', color:'#fff', padding:'6px 12px', borderRadius:'4px', 
               textDecoration:'none', fontSize:'12px', fontWeight:'bold', display:'flex', alignItems:'center', gap:'6px'
             }}>
               <MessageSquare size={14} /> Discord
             </a>
          </div>
        </div>
      )}

      {/* 🔥 THE MAIN GRID */}
      <div className={`match-grid ${cinemaMode ? 'cinema-active' : ''}`} style={{
        display: 'grid',
        gridTemplateColumns: cinemaMode ? '1fr' : '1fr 340px', // Hides chat col in cinema mode
        gap: '20px',
        maxWidth: '1600px',
        margin: '0 auto',
        padding: '0 20px',
        transition: 'all 0.4s ease'
      }}>
        
        {/* === LEFT: PLAYER & TOOLS === */}
        <div className="player-section" style={{maxWidth: cinemaMode ? '1200px' : '100%', margin: cinemaMode ? '0 auto' : '0'}}>
            
            {/* CINEMA TOGGLE (Floating above player) */}
            <div style={{display:'flex', justifyContent:'flex-end', marginBottom:'10px'}}>
              <button 
                onClick={() => setCinemaMode(!cinemaMode)}
                style={{
                  background: cinemaMode ? 'rgba(255,255,255,0.1)' : 'transparent',
                  color: cinemaMode ? '#8db902' : '#666',
                  border: '1px solid #333',
                  padding: '6px 12px',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  fontSize: '11px',
                  fontWeight: 'bold',
                  textTransform: 'uppercase'
                }}
              >
                {cinemaMode ? <Minimize size={14}/> : <Maximize size={14}/>}
                {cinemaMode ? "Exit Cinema" : "Cinema Mode"}
              </button>
            </div>

            {/* 🎥 THE VIDEO PLAYER */}
            <MatchPlayer matchId={matchId} />
            
            {/* 📊 MATCH INFO BAR */}
            <MatchInfo matchId={matchId} />

            {/* 🛠️ TOOLS: SHARE & EMBED (Hidden in Cinema Mode) */}
            {!cinemaMode && (
              <div style={{marginTop:'20px', background:'#0a0a0a', border:'1px solid #1a1a1a', borderRadius:'8px', padding:'15px'}}>
                <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'15px'}}>
                  
                  {/* Share Buttons */}
                  <div style={{display:'flex', gap:'10px', alignItems:'center'}}>
                    <span style={{color:'#666', fontSize:'12px', fontWeight:'bold', textTransform:'uppercase'}}>Share:</span>
                    <button style={{background:'#1DA1F2', border:'none', borderRadius:'4px', padding:'6px', cursor:'pointer'}}><Twitter size={16} color="#fff"/></button>
                    <button style={{background:'#25D366', border:'none', borderRadius:'4px', padding:'6px', cursor:'pointer'}}><MessageSquare size={16} color="#fff"/></button>
                    <button style={{background:'#1877F2', border:'none', borderRadius:'4px', padding:'6px', cursor:'pointer'}}><Facebook size={16} color="#fff"/></button>
                  </div>

                  {/* Embed Toggle */}
                  <button 
                    onClick={() => setShowEmbed(!showEmbed)}
                    style={{background:'#222', border:'1px solid #333', color:'#ccc', padding:'6px 12px', borderRadius:'4px', fontSize:'12px', cursor:'pointer', display:'flex', gap:'6px', alignItems:'center'}}
                  >
                    <Share2 size={14} /> Embed Stream
                  </button>
                </div>

                {/* Embed Code Box (Collapsible) */}
                {showEmbed && (
                  <div style={{marginTop:'15px', background:'#000', padding:'10px', borderRadius:'6px', border:'1px solid #222', display:'flex', gap:'10px'}}>
                    <input 
                      readOnly 
                      value={embedCode} 
                      style={{background:'transparent', border:'none', color:'#888', width:'100%', fontSize:'11px', fontFamily:'monospace'}} 
                    />
                    <button onClick={handleCopy} style={{background:'transparent', border:'none', cursor:'pointer', color: copied ? '#8db902' : '#fff'}}>
                      {copied ? <CheckCircle size={16} /> : <Copy size={16} />}
                    </button>
                  </div>
                )}
              </div>
            )}
        </div>

        {/* === RIGHT: CHAT SECTION (Hidden in Cinema Mode) === */}
        {!cinemaMode && (
          <div className="chat-panel" style={{height:'600px', display:'flex', flexDirection:'column', background:'#0a0a0a', border:'1px solid #1a1a1a', borderRadius:'8px', overflow:'hidden', position:'relative'}}>
              
              {/* CHAT HEADER */}
              <div className="chat-header" style={{padding:'10px 15px', borderBottom:'1px solid #222', display:'flex', justifyContent:'space-between', alignItems:'center', background:'#0f0f0f'}}>
                  <span style={{color:'#fff', fontWeight:'bold', fontSize:'13px'}}>Live Chat</span>
                  <div className="live-indicator" style={{display:'flex', alignItems:'center', gap:'6px', fontSize:'11px', color:'#888'}}>
                    <div className="live-dot" style={{width:'6px', height:'6px', background:'red', borderRadius:'50%'}}></div> 
                    1.2k Online
                  </div>
              </div>
              
              {/* CHAT CONTENT CONTAINER */}
              <div style={{flex:1, position:'relative', background:'#050505'}}>
                
                {/* 🔒 THE "GOOD BOY" BLUR OVERLAY */}
                {!chatAgreed && (
                  <div style={{
                    position:'absolute', top:0, left:0, width:'100%', height:'100%', 
                    background:'rgba(5,5,5,0.85)', backdropFilter:'blur(4px)', zIndex:10,
                    display:'flex', flexDirection:'column', justifyContent:'center', alignItems:'center', padding:'20px', textAlign:'center'
                  }}>
                    <AlertTriangle size={32} color="#8db902" style={{marginBottom:'10px'}} />
                    <h3 style={{color:'#fff', fontSize:'14px', margin:'0 0 5px 0'}}>Community Rules</h3>
                    <p style={{color:'#888', fontSize:'11px', lineHeight:'1.4', marginBottom:'15px'}}>
                      1. No hate speech or abuse.<br/>
                      2. Respect other users.<br/>
                      3. Don't spam links.
                    </p>
                    <button 
                      onClick={() => setChatAgreed(true)}
                      style={{
                        background:'#8db902', color:'#000', border:'none', padding:'8px 20px', 
                        borderRadius:'4px', fontSize:'12px', fontWeight:'bold', cursor:'pointer'
                      }}
                    >
                      I Agree
                    </button>
                  </div>
                )}

                {/* 💬 PLACEHOLDER FOR CBOX (We will replace this later) */}
                <div className="chat-messages" style={{padding:'15px', height:'100%', overflowY:'auto'}}>
                  <div className="chat-msg system" style={{color:'#444', fontSize:'11px', marginBottom:'8px', fontStyle:'italic'}}>Welcome to the chat room.</div>
                  <div className="chat-msg" style={{marginBottom:'6px', fontSize:'12px'}}><span style={{color:'#8db902', fontWeight:'bold', marginRight:'6px'}}>User192:</span><span style={{color:'#ccc'}}>Stream looks clean today</span></div>
                  <div className="chat-msg" style={{marginBottom:'6px', fontSize:'12px'}}><span style={{color:'#4a9eff', fontWeight:'bold', marginRight:'6px'}}>Alex:</span><span style={{color:'#ccc'}}>Lets go team!!</span></div>
                  <div className="chat-msg" style={{marginBottom:'6px', fontSize:'12px'}}><span style={{color:'#ff4444', fontWeight:'bold', marginRight:'6px'}}>Mod:</span><span style={{color:'#ccc'}}>No spamming links please.</span></div>
                </div>

              </div>

              {/* INPUT AREA */}
              <div className="chat-input-area" style={{padding:'10px', borderTop:'1px solid #222', background:'#0f0f0f'}}>
                  <input 
                    type="text" 
                    className="chat-input" 
                    placeholder={chatAgreed ? "Type a message..." : "Agree to rules to chat"} 
                    disabled={!chatAgreed}
                    style={{width:'100%', background:'#050505', border:'1px solid #222', padding:'8px 12px', borderRadius:'4px', color:'#fff', fontSize:'12px', outline:'none'}} 
                  />
              </div>
          </div>
        )}

      </div>
    </div>
  )
}

export default function MatchPage() {
  return (
    <Suspense fallback={<div style={{color:'#444', textAlign:'center', marginTop:'50px'}}>Initializing Arena...</div>}>
        <MatchPageContent />
    </Suspense>
  )
}